实验内容mmap(hard)最后的实验要求我们实现最基础的 mmap 功能，也就是将一个文件直接映射到内存中，之后通过直接读写内存来读写文件，可以大大提升需要频繁读写的文件的处理效率。
首先照例注册 mmap 和 munmap 系统调用，接下来定义用于保存内存映射信息的结构体 struct vma，每个进程分配 NVMA 个结构体。struct vma&#123;  uint64 addr;  uint64 length;  int prot;  int flags;  int fd;  int offset;  struct file *file;&#125;;struct proc&#123;    ···    struct vma vmas[NVMA];         // Virtual memory areas&#125;
接下来处理 mmap 函数，对于权限要求不合法的情况进行拒绝。在我的 vma 中默认 length = 0 代表 vma 无效，找到一个空位后就可以进行初始化了。在这里我们并不会分配内存，而是在触发缺页异常的时候才进行分配。我们给用户程序提供用户空间中的虚拟地址 v-&gt;addr 作为文件的起始位置，记得要增长 p-&gt;sz 和对文件进行引用，而且 length, addr 和 p-&gt;sz 都要对齐。uint64sys_mmap(void)&#123;  uint64 addr;  int length, prot, flags, fd, offset;  struct file* f;  if (argaddr(0, &amp;addr) &lt; 0 || argint(1, &amp;length) &lt; 0 || argint(2, &amp;prot) &lt; 0      || argint(3, &amp;flags) &lt; 0 || argfd(4, &amp;fd, &amp;f) &lt; 0 || argint(5, &amp;offset) &lt; 0)    return -1;    if(addr != 0)    panic(&quot;mmap: addr not 0&quot;);  if(offset != 0)    panic(&quot;mmap: offset not 0&quot;); // required by xv6  struct proc *p = myproc();  struct file *file = p-&gt;ofile[fd];  if ((prot &amp; PROT_READ) &amp;&amp; !f-&gt;readable)    return -1; // can&#x27;t read from write-only file  if ((prot &amp; PROT_WRITE) &amp;&amp; !f-&gt;writable &amp;&amp; flags == MAP_SHARED)    return -1; // can&#x27;t write to read-only file  for(int i = 0; i &lt; NVMA; i++)  &#123;    if (p-&gt;vmas[i].length == 0)    &#123;      struct vma *v = &amp;p-&gt;vmas[i];      v-&gt;addr = p-&gt;sz;      v-&gt;length = PGROUNDUP(length);      v-&gt;prot = prot;      v-&gt;flags = flags;      v-&gt;fd = fd;      v-&gt;offset = offset;      v-&gt;file = file;      filedup(file);      p-&gt;sz += v-&gt;length;      return v-&gt;addr;    &#125;  &#125;  return -1;&#125;
然后在触发缺页异常时进行页面分配，这里的处理逻辑一定要严谨，不然就算过了 mmaptest 也有可能在 usertest 里面遇到访问非法地址导致缺页但不需要分配页面的情况，这时候会卡死。大致思路是先判掉本身就不可能触发缺页异常的地址，然后搜索 vmas，如果找不到同样得判掉。找到了就进行常规的页面分配，然后用 readi 从文件中读入一页。这里我们处理了偏移量非零的情况，实际上因为实验要求也可以不管。···  else if(r_scause() == 13 || r_scause() == 15)  &#123;    //panic(&quot;here&quot;);    uint64 va = r_stval();    struct proc *p = myproc();    if(va &gt;= MAXVA || va &gt; p-&gt;sz)      p-&gt;killed = 1;    else    &#123;      va = PGROUNDDOWN(va);      int found = 0;      for(int i = 0; i &lt; NVMA; i++)      &#123;        struct vma *vma = &amp;p-&gt;vmas[i];        if (vma-&gt;length == 0)          continue;        if (va &gt;= vma-&gt;addr &amp;&amp; va &lt; vma-&gt;addr + vma-&gt;length)        &#123;          found = 1;          uint64 pa = (uint64)kalloc();          if (pa == 0)          &#123;            p-&gt;killed = 1;            break;          &#125;          memset((void*)pa, 0, PGSIZE);          int flag = (vma-&gt;prot &lt;&lt; 1) | PTE_U | PTE_V;          if (mappages(p-&gt;pagetable, va, PGSIZE, pa, flag) != 0)          &#123;            //printf(&quot;???&quot;);            kfree((void*)pa);            p-&gt;killed = 1;            break;          &#125;          struct inode *ip = vma-&gt;file-&gt;ip;          ilock(ip);          readi(ip, 0, pa, vma-&gt;offset + (va - vma-&gt;addr), PGSIZE);          iunlock(ip);          break;        &#125;      &#125;      if (!found)        p-&gt;killed = 1;    &#125;  &#125;···
接下来实现 munmap，这也是整个实验中最复杂的一部分。我们分三种情况进行处理，只删除一部分的情况是简单的，只需要修改 v-&gt;addr 和 v-&gt;length 即可，全部删除的话还需要关闭文件。然后我们用 uvmunmap 解除映射关系并且释放物理内存。如果有共享标签，那么就还要对文件进行修改，这一部分比较复杂，我们单独用 vmafilewrite 函数来处理。uint64sys_munmap(void)&#123;  uint64 addr;  int length, offset;  if (argaddr(0, &amp;addr) &lt; 0 || argint(1, &amp;length) &lt; 0) &#123;    return -1;  &#125;  struct proc *p = myproc();  int close = 0;  for(int i = 0; i &lt; NVMA; i++)  &#123;    struct vma *v = &amp;p-&gt;vmas[i];    if (v-&gt;length == 0)      continue;    if (addr &gt;= v-&gt;addr &amp;&amp; addr &lt; v-&gt;addr + v-&gt;length)    &#123;      offset = addr - v-&gt;addr;      addr = PGROUNDDOWN(addr);      // printf(&quot;addr: %p, v-&gt;addr: %p,length: %d, v-&gt;length: %d\n&quot;, addr, v-&gt;addr, length,v-&gt;length);      if(addr == v-&gt;addr)      &#123;        if(length &gt;= v-&gt;length)        &#123;          close = 1;          length = v-&gt;length;          v-&gt;length = 0;        &#125;        else        &#123;          v-&gt;addr += length;          v-&gt;length -= length;        &#125;      &#125;      else      &#123;        length = v-&gt;length - (addr - v-&gt;addr);        v-&gt;length -= length;      &#125;      if(v-&gt;flags == MAP_SHARED)      &#123;        struct file *ip = v-&gt;file;        if(vmafilewrite(ip, addr, length, offset) &lt; 0)          return -1;      &#125;      // printf(&quot;addr: %p, v-&gt;addr: %p,length: %d, v-&gt;length: %d\n&quot;, addr, v-&gt;addr, length,v-&gt;length);      uvmunmap(p-&gt;pagetable, addr, PGROUNDUP(length)/PGSIZE, 1);      // printf(&quot;here2\n&quot;);      if(close)      &#123;        fileclose(v-&gt;file);        v-&gt;file = 0;      &#125;      break;    &#125;  &#125;  return 0;&#125;
vmawrite 是要我们对文件进行写入，我们不难发现这个功能跟 filewrite 的功能是很像的。但 filewrite 不支持从给定偏移量修改，所以我们把写入文件的部分抄过来，再做一点小小的改动。这里其实可以根据页面是否被写入过做一些优化，但我们这里并没有实现这个功能。intvmafilewrite(struct file *f, uint64 addr, int n, int offset)&#123;  int r;  if(f-&gt;writable == 0)    return -1;  int max = ((MAXOPBLOCKS-1-1-2) / 2) * BSIZE;  // printf(&quot;max: %d\n&quot;, max);  int i = 0;  while(i &lt; n)  &#123;    int n1 = n - i;    if(n1 &gt; max)      n1 = max;    begin_op();    ilock(f-&gt;ip);    if ((r = writei(f-&gt;ip, 1, addr + i, offset, n1)) &gt; 0)      offset += r;    iunlock(f-&gt;ip);    end_op();    if(r != n1)    &#123;      // error from writei      break;    &#125;    i += r;  &#125;  return 0;&#125;
还有一个小的注意点：有缺页异常的时候 uvmunmap 和 uvmcopy 的逻辑要修改。跟之前写时复制分支的处理一样，在遇到无效页面时不能报错。···if((*pte &amp; PTE_V) == 0)    continue;···
接着修改 exit，当进程退出时我们也要对 vma 进行回收。···for(int i = 0; i &lt; NVMA; i++)&#123;    struct vma *v = &amp;p-&gt;vmas[i];    if (v-&gt;length == 0)        continue;    if(v-&gt;flags == MAP_SHARED)    &#123;        struct file *ip = v-&gt;file;        if(vmafilewrite(ip, v-&gt;addr, v-&gt;length, v-&gt;offset) &lt; 0)        continue;    &#125;    uvmunmap(p-&gt;pagetable, v-&gt;addr, PGROUNDUP(v-&gt;length)/PGSIZE, 1);    fileclose(v-&gt;file);    v-&gt;file = 0;&#125;begin_op();iput(p-&gt;cwd);end_op();p-&gt;cwd = 0;
最后修改 fork，将 vma 的内容复制过来。···for(i = 0; i &lt; NVMA; i++)&#123;    np-&gt;vmas[i].length = 0;    if(p-&gt;vmas[i].length)    &#123;        memmove(&amp;np-&gt;vmas[i], &amp;p-&gt;vmas[i], sizeof(struct vma));        filedup(np-&gt;vmas[i].file);    &#125;&#125;safestrcpy(np-&gt;name, p-&gt;name, sizeof(p-&gt;name));···
至此 mmap 和 munmap 得以实现，我们实现了简单的内存映射文件。
小结完结撒花！操作系统之旅大概暂时就到这里，花了大概两个月的时间……其实看中间的其他博客你就知道为什么拖了这么久了……这是进大学以来完整（大概）自学的第一门公开课，之前试图学 MIT-Missing-Semester 不知道为啥就咕咕咕了，总之学完了还是相当开心的啦。通过 XV6 这个简单的操作系统，我对操作系统的大致结构有了基本的了解，也学到了一些常见的处理技巧，收获算是相当不错。感觉最方便的调试方式还是直接输出），gdb 什么的真不熟吧（笑）。接下来大概是 cs143？希望自己还能坚持下去，又义无反顾地投向下一个坑了呢。
