实验任务Eliminate allocation from sbrk() (easy)呃，真就一行……把...if(growproc(n) &lt; 0)    return -1;...改成...myproc()-&gt;sz += n;...就行了
Lazy allocation (moderate)第二部分要我们实现最简单的懒分配，我们在每次出现缺页异常（scause=13是读异常，scause=15是写异常）的时候，进行分配需要的虚拟地址所在的页面即可。这里不需要修改 p-&gt;trapframe-&gt;epc 是因为我们需要重试原指令。...else if(r_scause() == 13 || r_scause() == 15)&#123;    uint64 va = r_stval();    if(lazy_alloc(va) &lt; 0)      p-&gt;killed = 1;  &#125;...lazy_alloc 函数如下，因为每次只分配一页所以不需要 uvmdealloc 来解决分配很多页时内存不够的情况。intlazy_alloc(uint64 addr)&#123;  char * mem;  struct proc * p = myproc();  //printf(&quot;heh1&quot;);  if(addr &gt;= p-&gt;sz)  &#123;    return -1;  &#125;  if(addr &lt; p-&gt;trapframe-&gt;sp)  &#123;    return -2;  &#125;  addr = PGROUNDDOWN(addr);  mem = kalloc();  if(mem == 0)  &#123;    return -3;  &#125;  memset(mem, 0, PGSIZE);  if(mappages(p-&gt;pagetable, addr, PGSIZE, (uint64)mem, PTE_W|PTE_X|PTE_R|PTE_U) != 0)  &#123;    kfree(mem);    return -4;  &#125;  return 0;&#125;最后我们需要修改 uvmunmap 的逻辑，因为我们进行了懒分配，所以会出现未分配页需要释放的可能，这时候我们跳过即可。uvmunmap(pagetable_t pagetable, uint64 va, uint64 npages, int do_free)&#123;  uint64 a;  pte_t *pte;  if((va % PGSIZE) != 0)    panic(&quot;uvmunmap: not aligned&quot;);  for(a = va; a &lt; va + npages*PGSIZE; a += PGSIZE)&#123;    if((pte = walk(pagetable, a, 0)) == 0)      panic(&quot;uvmunmap: walk&quot;);    if((*pte &amp; PTE_V) == 0)      continue; // 需要释放的情况    if(PTE_FLAGS(*pte) == PTE_V)      panic(&quot;uvmunmap: not a leaf&quot;);    if(do_free)&#123;      uint64 pa = PTE2PA(*pte);      kfree((void*)pa);    &#125;    *pte = 0;  &#125;&#125;
Lazytests and Usertests (moderate)第三部分就是一些没处理的细节。我们首先处理 sbrk 为负数的情形，因为之前已经修改了 uvmdealloc，所以直接释放就行。uint64sys_sbrk(void)&#123;  struct proc * p = myproc();  int addr;  int n;  if(argint(0, &amp;n) &lt; 0)    return -1;  addr = p-&gt;sz;  if(n &gt; 0)    p-&gt;sz += n;  else    p-&gt;sz = uvmdealloc(p-&gt;pagetable, addr, addr + n);  return addr;&#125;
sbrk 越界的情形已在第二部分解决，接下来修改复制进程需要用到的 fork。我们需要修改其调用的 uvmcopy，在找不到pte的时候不再报错。...for(i = 0; i &lt; sz; i += PGSIZE)&#123;    if((pte = walk(old, i, 0)) == 0)        continue;    if((*pte &amp; PTE_V) == 0)        continue;    pa = PTE2PA(*pte);    flags = PTE_FLAGS(*pte);    if((mem = kalloc()) == 0)        goto err;    memmove(mem, (char*)pa, PGSIZE);    if(mappages(new, i, PGSIZE, (uint64)mem, flags) != 0)&#123;        kfree(mem);        goto err;    &#125;&#125;return 0;..
然后修改 read 和 write 的系统调用。通过对流程的分析可知，在操作系统中，当用户态程序执行 read/write 系统调用陷入内核时，RISC-V 架构的 scause 寄存器会记录环境调用异常代码8。我们要防止在内核中需要地址时页面未分配的情况。事实上，他们均通过 walkaddr 函数解析用户虚拟地址对应的物理地址，此过程需要主动遍历用户页表，其执行路径与硬件自动触发的缺页异常处理机制存在本质差异。所以我们需要修改 walkaddr 的逻辑，在找不到pte时分配页面。uint64walkaddr(pagetable_t pagetable, uint64 va)&#123;  pte_t *pte;  uint64 pa;  if(va &gt;= MAXVA)    return 0;  pte = walk(pagetable, va, 0);  if(pte == 0 || (*pte &amp; PTE_V) == 0)  &#123;    if(lazy_alloc(va) == 0)      pte = walk(pagetable, va, 0);    else        return 0;  &#125;  if((*pte &amp; PTE_U) == 0)    return 0;  pa = PTE2PA(*pte);  return pa;&#125;
小结至此Lab5宣告结束，总体来说比较轻松（而且没有文档要看真的很爽啊哈哈哈哈！）。通过对懒分配的实现，我们对陷阱的机制有了更深的了解，还了解到 walkaddr 通过主动遍历用户页表来定位pte，跟用户态的 load/store 指令是独立的逻辑，因此不会触发缺页异常。这种差异性带来的隔离性实在是令人叹为观止。唔，test项目太多了懒得放通过截图了。

代码实现Cool 语言跟 Java 相当相似，语法简单清晰，强调类型和类结构。PA1 要求实现一个简单的栈机器，目的是熟悉语言，但有几个需要注意的地方：

每个类方法都由表达式定义，求值结果即为方法的返回值。因此，常见的写法是在大括号中嵌套代码块，代码块内部用 ; 分隔表达式。类方法定义结束后，需在闭合大括号 &#125; 之后添加分号 ;。

if、while 等控制结构本质上也是表达式，具有返回值，并且结构比较严格。如果要包含多个表达式作为分支体或循环体，需使用代码块 &#123;&#125; 包裹，写法上与类方法类似。

局部变量必须使用 let 关键字进行定义，不能直接赋值给未声明的变量。


实现比较简单，我们用 StackNode 类来实现栈，每个节点储存命令信息和下一个节点的地址。注意 Cool 语言强制属性为 private，方法为 public，因此只能通过方法来访问属性。
class StackNode&#123;   command: StackCommand;   next: StackNode;   init(co:StackCommand, ne:StackNode): StackNode&#123;      &#123;         command &lt;- co;         next &lt;- ne;         self;      &#125;   &#125;;   getCommand(): StackCommand &#123;      command   &#125;;   getNext(): StackNode &#123;      next   &#125;;   setNext(node: StackNode): StackNode &#123;      next &lt;- node   &#125;;   putOnTop(co: StackCommand): StackNode &#123;      let newNode: StackNode in &#123;         newNode &lt;- (new StackNode).init(co, self);         newNode;      &#125;   &#125;;&#125;;
然后实现命令，用 StackCommand 作为模板，每个命令或是返回数字，或是返回符号，或是执行命令。class StackCommand&#123;   execute(node:StackNode): StackNode&#123;      let err: StackNode in&#123;         (new IO).out_string(&quot;Undefined Execution!&quot;);         err;      &#125;   &#125;;   getNumber(): Int &#123;      0   &#125;;   getChar(): String &#123;      &quot;Called from base class&quot;   &#125;;&#125;;
分别实现三种命令，注意 if 指令要完整。
IntCommand inherits StackCommand &#123;   number: Int;   init(num: Int): SELF_TYPE&#123;      &#123;         number &lt;- num;         self;      &#125;   &#125;;   execute(node:StackNode): StackNode&#123;      node   &#125;;   getNumber(): Int &#123;      number   &#125;;   getChar(): String &#123;      (new A2I).i2a(number)   &#125;;&#125;;class PlusCommand inherits StackCommand &#123;   init(): SELF_TYPE&#123;      self   &#125;;   execute(node:StackNode): StackNode&#123;      let n1: StackNode &lt;- node.getNext(),         n2: StackNode &lt;- n1.getNext(),         sum: Int,         ret: StackNode in&#123;            if (not (isVoid n1)) then               if (not (isVoid n2)) then&#123;                  sum &lt;- n1.getCommand().getNumber() + n2.getCommand().getNumber();                  ret &lt;- (new StackNode).init((new IntCommand).init(sum), n2.getNext());               &#125;               else                  0               fi            else               0            fi;            ret;      &#125;   &#125;;   getChar(): String &#123;      &quot;+&quot;   &#125;;&#125;;class SwapCommand inherits StackCommand &#123;   init(): SELF_TYPE&#123;      self   &#125;;   execute(node:StackNode): StackNode&#123;      let n1: StackNode &lt;- node.getNext(),         n2: StackNode &lt;- n1.getNext(),         ret: StackNode in&#123;            node &lt;- n1;            node.setNext(n2.getNext());            n2.setNext(node);            n2;      &#125;   &#125;;   getChar(): String &#123;      &quot;s&quot;   &#125;;&#125;;
最后实现 main 函数，根据要求进行调用即可：class Main inherits A2I &#123;   stackTop: StackNode;   printStack(): Object &#123;      let node: StackNode &lt;- stackTop in &#123;         while (not (isvoid node)) loop         &#123;            (new IO).out_string(node.getCommand().getChar());            (new IO).out_string(&quot;\n&quot;);            node &lt;- node.getNext();         &#125;         pool;      &#125;   &#125;;   pushCommand(command: StackCommand): StackCommand &#123;      &#123;         if (isvoid stackTop) then &#123;            let nil: StackNode in &#123;               stackTop &lt;- (new StackNode).init(command, nil);            &#125;;         &#125; else &#123;            stackTop &lt;- stackTop.putOnTop(command);         &#125; fi;         command;      &#125;   &#125;;   executeStack(inString: String): Object &#123;      &#123;         if (inString = &quot;+&quot;) then         &#123;            pushCommand((new PlusCommand).init());         &#125;         else            if (inString = &quot;s&quot;) then               pushCommand((new SwapCommand).init())            else               if (inString = &quot;d&quot;) then                  printStack()               else                  if (inString = &quot;x&quot;) then                     -- stop                     &#123;                        (new IO).out_string(&quot;stop!\n&quot;);                        abort();                     &#125;                  else                     if (inString = &quot;e&quot;) then                        let node: StackNode &lt;- stackTop in &#123;                           if (not (isvoid node)) then                              stackTop &lt;- node.getCommand().execute(node)                           else                              0                           fi;                        &#125;                     else                        pushCommand((new IntCommand).init((new A2I).a2i(inString)))                     fi                  fi               fi            fi         fi;      &#125;   &#125;;   main() : Object &#123;      let inString: String in &#123;         while (true) loop         &#123;            (new IO).out_string(&quot;&gt;&quot;);            inString &lt;- (new IO).in_string();            executeStack(inString);         &#125;         pool;      &#125;   &#125;;&#125;;
小结代码没啥复杂度，写的目的单纯是为了熟悉 Cool 语言，重头戏还在后头嘞~
